INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2e_L4_C', 'RC2e', 4, 'C', 'Explaining a Chain Reaction', 'Printed passage', 'Read this story. One thing causes another, which causes another! Tell me the chain reaction: what was the very first cause, and what was the very last effect?', 'Child traces a multi-step cause-and-effect chain from beginning to end.', 'If they miss a step, help them map it: ''A caused B, and B caused...?''', 'How did the first event lead all the way to the end of the story?', '{"default":{"theme":"domino effect"},"ug":{"theme":"domino effect at the market"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2e_L4_M', 'RC2e', 4, 'M', 'Analyzing Real-World Rules', 'A printed list of household rules, Paper, Pencil', 'Here is a list of rules for the house. Choose one rule. Write a sentence explaining what the rule is, and what the effect will be if you don''t follow it.', 'Child extracts a rule and logically infers or extracts the consequence (effect).', 'Do not correct during the task. If they fail to link cause and effect, review Execute level.', 'Why do rules usually have effects connected to them?', '{"default":{"theme":"house rules"},"ug":{"theme":"house rules"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2f_L1_A', 'RC2f', 1, 'A', 'Auditory Emotion Identification', 'None', 'Listen to my voice when I read this: ''Oh no! I lost my favorite book!'' How does the character feel?', 'Child correctly identifies the feeling (sad, upset, worried).', 'If they say ''happy'', read it again emphasizing the distress in the tone.', 'What words helped you know how they felt?', '{"default":{"feeling":"sad"},"ug":{"feeling":"sad"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2f_L1_B', 'RC2f', 1, 'B', 'Physical Emotion Matching', 'Printed passage, Cards with simple face drawings (happy, sad, angry, scared)', 'I''m going to read a short story about Tendo. When I finish, hold up the face card that shows how Tendo feels at the end of the story.', 'Child holds up the appropriate emotion card based on the text.', 'If incorrect, ask them what happened at the end of the story to make them choose that face.', 'Why did you choose the scared face? What happened in the story?', '{"default":{"character":"Sam","emotion":"scared"},"ug":{"character":"Tendo","emotion":"scared"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2f_L1_C', 'RC2f', 1, 'C', 'Action to Trait Verbal Link', 'None', 'If a character shares their lunch with a friend who doesn''t have any, are they ''greedy'' or ''generous''?', 'Child correctly identifies ''generous'' (or kind).', 'If they don''t know the words, define them and ask again.', 'How does sharing lunch show that someone is generous?', '{"default":{"action":"sharing lunch"},"ug":{"action":"sharing roasted maize"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2f_L2_A', 'RC2f', 2, 'A', 'Writing a Feeling', 'Paper, Pencil, Printed passage', 'Read the story. How did Amara feel when she won the race? Say the feeling in a sentence, then write it.', 'Child writes a sentence identifying the character''s emotion.', 'If they just write ''happy'', prompt them to write a full sentence.', 'What word in the story told you she was happy?', '{"default":{"character":"Alex","event":"won race"},"ug":{"character":"Amara","event":"won race"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2f_L2_B', 'RC2f', 2, 'B', 'Writing Evidence for a Trait', 'Paper, Pencil, Printed passage', 'Read the passage. The author says the boy is ''hardworking''. Find the sentence that PROVES he is hardworking. Say it, then write it down.', 'Child locates and writes the text evidence supporting the given trait.', 'If they write a detail unrelated to working hard, ask: ''Does that show he works hard?''', 'Why does sweeping the whole compound show that someone is hardworking?', '{"default":{"trait":"hardworking","action":"cleaning"},"ug":{"trait":"hardworking","action":"sweeping the compound"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2f_L2_C', 'RC2f', 2, 'C', 'Tracking Changing Feelings', 'Paper, Pencil, Printed passage', 'Read the story. The character''s feelings change from the beginning to the end. Write one sentence about how they felt at the start, and one about how they felt at the end.', 'Child writes two sentences tracking the emotional shift.', 'If they miss the shift, ask: ''Did they feel the same way the whole time?''', 'What happened in the middle of the story to make their feelings change?', '{"default":{"shift":"sad to happy"},"ug":{"shift":"worried to relieved"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2f_L3_A', 'RC2f', 3, 'A', 'Detecting Trait vs Feeling', 'Printed passage', 'Read this paragraph. Someone said, ''The character is feeling tall.'' Wait, ''tall'' is how they look, not how they feel. What is a word from the story that tells how they ACTUALLY feel?', 'Child differentiates between a physical trait and an emotion.', 'If they struggle, ask: ''Can you feel tall? Or do you feel happy/sad?''', 'What is the difference between how someone looks and how someone feels?', '{"default":{"physical":"tall","emotion":"proud"},"ug":{"physical":"tall","emotion":"proud"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2f_L3_B', 'RC2f', 3, 'B', 'Evaluating Evidence', 'Printed passage, Paper, Pencil', 'Read the story. A student wrote: ''Tendo is mean because he has a dog.'' Does having a dog prove someone is mean? Write a better sentence proving he is mean using evidence from the text.', 'Child rejects the illogical evidence and writes a sentence using valid text evidence.', 'If they can''t find evidence, ask them what Tendo did to the other children in the story.', 'Why is your evidence better than the first student''s evidence?', '{"default":{"character":"Sam","trait":"mean"},"ug":{"character":"Tendo","trait":"mean"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2f_L3_C', 'RC2f', 3, 'C', 'Spotting Emotion Mismatch', 'Printed passage', 'Look at this sentence: ''Amara cried big tears because she was so excited.'' Does that make sense? Sometimes people cry when they are happy, but usually, tears mean something else. What word should probably replace ''excited''?', 'Child suggests an appropriate emotion like sad, upset, or hurt.', 'If they say ''happy'', explain the context usually implies sadness.', 'Why do authors need to make sure the actions match the feelings?', '{"default":{"character":"Alex","action":"cried"},"ug":{"character":"Amara","action":"cried"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2f_L4_A', 'RC2f', 4, 'A', 'Writing Actions to Show Traits', 'Paper, Pencil', 'I want you to invent a character who is ''lazy''. But you cannot use the word ''lazy'' in your sentence! Write a sentence showing them doing something that PROVES they are lazy.', 'Child writes a sentence describing an action indicative of laziness (e.g., sleeping all day).', 'If they use the word ''lazy'', remind them of the constraint.', 'How does your sentence ''show'' instead of ''tell''?', '{"default":{"trait":"lazy"},"ug":{"trait":"lazy"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2f_L4_B', 'RC2f', 4, 'B', 'Writing Dialogue for Feelings', 'Paper, Pencil', 'Think of a character who is very angry. Write one sentence of exactly what they would say out loud. Use an exclamation mark!', 'Child writes dialogue reflecting anger, properly punctuated.', 'If the dialogue sounds happy or calm, ask: ''If you were mad, is that how you would say it?''', 'How does the exclamation mark help show the feeling?', '{"default":{"emotion":"angry"},"ug":{"emotion":"angry"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2f_L4_C', 'RC2f', 4, 'C', 'Analyzing Parent-Provided Trait', 'Printed passage', 'Read the story. I think the main character is ''curious'' (they like to know things). Do you agree or disagree? Explain why using events from the story.', 'Child defends or refutes the assigned trait using text evidence.', 'If they just say ''I agree'' without evidence, demand proof.', 'What is the strongest piece of evidence you have to support your opinion?', '{"default":{"trait":"curious"},"ug":{"trait":"curious"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2f_L4_M', 'RC2f', 4, 'M', 'Characterizing from a Letter', 'A printed letter, Paper, Pencil', 'Read this letter written by a child to their grandmother. Based on what they wrote, pick one word to describe the child (like kind, polite, selfish, or funny). Write the word, and write one sentence explaining why you picked it.', 'Child infers a character trait from the tone and content of a letter and supports it.', 'Do not correct during the task. If they fail to infer a trait, review Execute level.', 'Can you tell what kind of person someone is just by reading a letter they wrote?', '{"default":{"format":"letter to grandma"},"ug":{"format":"letter to Jajja (grandmother)"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2g_L1_A', 'RC2g', 1, 'A', 'Auditory Inference', 'None', 'Listen to this: ''Amara put on her boots, grabbed her umbrella, and ran outside.'' Did the story say it was raining?', 'Child correctly answers no, but infers that it is raining.', 'If they say yes, read it again and ask: ''Did I actually say the word rain?''', 'How do you know it''s raining even though the author didn''t say it?', '{"default":{"character":"Alex","items":"boots and umbrella"},"ug":{"character":"Amara","items":"gumboots and umbrella"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2g_L1_B', 'RC2g', 1, 'B', 'Physical Clue Matching', 'Printed passage, Picture cards: one of a sunny beach, one of a snowy mountain, one of a rainy street', 'I''m going to read a story about what a boy packed in his suitcase: a heavy coat, mittens, and thick socks. Which picture shows where he is going?', 'Child selects the snowy mountain picture.', 'If they pick the beach, ask: ''Would you need a heavy coat at the beach?''', 'What clues in the story made you choose that picture?', '{"default":{"location":"snowy mountain"},"ug":{"location":"cold place like Kabale"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2g_L1_C', 'RC2g', 1, 'C', 'Verbal Prediction from Clues', 'None', 'Listen to this: ''Tendo''s dog started digging a hole near the fence. Tendo yelled, "No, stop!"'' What do you think the dog is trying to do?', 'Child infers the dog is trying to escape or bury something.', 'If they guess randomly, ask: ''Why would a dog dig near a fence?''', 'What makes you think the dog is doing that?', '{"default":{"animal":"dog"},"ug":{"animal":"dog"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2g_L2_A', 'RC2g', 2, 'A', 'Writing an Inference - Setting', 'Paper, Pencil, Printed passage', 'Read the story. It describes a place with lots of trees, birds singing, and a path made of dirt. The author never names the place. Where are they? Say it, then write it.', 'Child infers the setting (forest, woods, jungle) and writes it.', 'If they just list details, prompt: ''What do we call a place like that?''', 'What words helped you guess the setting?', '{"default":{"setting":"forest"},"ug":{"setting":"forest or village"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2g_L2_B', 'RC2g', 2, 'B', 'Writing an Inference - Problem', 'Paper, Pencil, Printed passage', 'Read the passage. Amara is looking everywhere for her shoes. She is running late. What is her problem? The text doesn''t say ''Her problem is...'', so you have to figure it out. Write it down.', 'Child writes a sentence describing the problem (e.g., she lost her shoes and is late).', 'If they miss the urgency, point out ''running late''.', 'Why is losing her shoes a problem right now?', '{"default":{"character":"Alex","problem":"lost shoes"},"ug":{"character":"Amara","problem":"lost shoes"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2g_L2_C', 'RC2g', 2, 'C', 'Explaining the Clues', 'Paper, Pencil, Printed passage', 'Read the story. The inference is ''The cake burned.'' Write down one clue from the story that proves this inference is true.', 'Child writes a detail like ''smoke coming from the oven'' or ''a bad smell''.', 'If they write ''the cake burned'', remind them we need the CLUE, not the inference.', 'Is your clue written directly in the story?', '{"default":{"theme":"burning food"},"ug":{"theme":"burning food (like chapati on a pan)"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2g_L3_A', 'RC2g', 3, 'A', 'Detecting a Bad Inference', 'Printed passage', 'Read this story about a boy who drops his ice cream. Someone inferred: ''He dropped it because he wanted to feed the ants.'' Is that a good inference or a silly guess?', 'Child identifies it as a silly guess/bad inference.', 'If they think it''s good, ask: ''Do people usually drop their treats on purpose to feed bugs?''', 'Why is that a bad inference?', '{"default":{"item":"ice cream"},"ug":{"item":"ice cream or mandazi"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2g_L3_B', 'RC2g', 3, 'B', 'Fact vs Inference Sort', 'Printed passage', 'Read the story. Are these facts (written in the text) or inferences (figured out)? 1. ''Tendo was crying.'' 2. ''Tendo was sad because his toy broke.''', 'Child correctly identifies the first as a fact and the second as an inference (if the text only says he cried over a broken toy).', 'If they confuse them, ask: ''Did the author write the exact word sad?''', 'What is the difference between a fact and an inference?', '{"default":{"character":"Sam","emotion":"sad"},"ug":{"character":"Tendo","emotion":"sad"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2g_L3_C', 'RC2g', 3, 'C', 'Finding the Missing Clue', 'Printed passage, Paper, Pencil', 'Read the passage. I made an inference: ''The girl is tired.'' But the story only says she went to bed. What detail could the author add to make my inference stronger? Write it down.', 'Child suggests a clue like ''she yawned'' or ''her eyes were heavy''.', 'If they suggest ''she said I am tired'', remind them inferences rely on showing, not telling.', 'How does your new detail help prove she is tired?', '{"default":{"action":"yawning"},"ug":{"action":"yawning"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2g_L4_A', 'RC2g', 4, 'A', 'Writing a Clue-Based Description', 'Paper, Pencil', 'Write a short paragraph describing an animal (like a cat or dog) without ever naming the animal! Use clues about what it looks like and sounds like.', 'Child writes a descriptive paragraph that allows the reader to infer the animal.', 'If they name the animal, make them erase the name and replace it with ''the animal''.', 'Read your paragraph to me. Can I guess what animal it is from your clues?', '{"default":{"theme":"mystery animal"},"ug":{"theme":"mystery animal (like a goat or chicken)"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2g_L4_B', 'RC2g', 4, 'B', 'Making a Complex Inference', 'Printed passage, Paper, Pencil', 'Read this story about two friends talking. They aren''t looking at each other, and their arms are crossed. How do they feel about each other right now? Write it down and give one reason why.', 'Child infers the friends are angry/fighting and cites the body language as evidence.', 'If they think they are happy, have them cross their own arms and look away.', 'How does body language help us make inferences?', '{"default":{"relationship":"fighting friends"},"ug":{"relationship":"fighting friends"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2g_L4_C', 'RC2g', 4, 'C', 'Explaining Inference', 'Printed passage', 'Explain to me what ''making an inference'' means. You can use the story we just read to help you explain.', 'Child articulates that an inference is using clues from the text plus what you already know to figure something out.', 'If they say ''guessing'', clarify the difference between a random guess and a smart guess using clues.', 'Why do authors sometimes make us infer things instead of just telling us?', '{"default":{"concept":"inference"},"ug":{"concept":"inference"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2g_L4_M', 'RC2g', 4, 'M', 'Inferring from a Real-World Scenario', 'A printed short dialogue, Paper, Pencil', 'Read this short conversation between a mother and child. Write down what you think just happened before they started talking. You have to figure it out from their words.', 'Child makes a logical inference about preceding events based on the dialogue.', 'Do not correct during the task. If they fail, review inference from clues.', 'What words did they say that gave you the biggest clue?', '{"default":{"theme":"spilled milk"},"ug":{"theme":"spilled tea or broken cup"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2h_L1_A', 'RC2h', 1, 'A', 'Auditory Comparison (Same/Different)', 'None', 'Listen to Story 1: ''The dog chased the cat.'' Listen to Story 2: ''The dog chased the ball.'' Are these stories exactly the same? What is different?', 'Child identifies the difference (cat vs ball).', 'If they say yes, emphasize the final words of each sentence.', 'What is the same about both stories?', '{"default":{"theme":"chasing"},"ug":{"theme":"chasing"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2h_L1_B', 'RC2h', 1, 'B', 'Physical Venn Diagram Sorting', 'Two printed passages, Two overlapping hoops or circles drawn on paper, Word cards (e.g., Dog, Cat, Both)', 'We have two short stories about pets. Place the ''Dog'' card in the circle for Story 1, the ''Cat'' card in Story 2''s circle. If something happens in BOTH stories, where does the card go?', 'Child places cards in the correct sections of the Venn diagram.', 'If they place ''Both'' in one circle, demonstrate the overlapping middle section.', 'Why does the middle part belong to both stories?', '{"default":{"theme":"pets"},"ug":{"theme":"animals (cows vs goats)"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2h_L1_C', 'RC2h', 1, 'C', 'Verbal Similarities', 'Two printed passages', 'I will read two short poems about rain. Tell me one thing that BOTH poems talk about.', 'Child identifies a common element (e.g., water, clouds, getting wet).', 'If they name something only in one poem, ask: ''Did the other poem talk about that?''', 'How are the two poems alike?', '{"default":{"theme":"rain"},"ug":{"theme":"rainy season"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2h_L2_A', 'RC2h', 2, 'A', 'Writing a Similarity', 'Paper, Pencil, Two printed passages', 'Read Story A about a boy building a fort, and Story B about a girl building a treehouse. Write one sentence telling me how the stories are the SAME.', 'Child writes a sentence describing a shared element (e.g., they both built something).', 'If they write a difference, remind them we are looking for ''same''.', 'Show me where both stories talk about building.', '{"default":{"theme":"building"},"ug":{"theme":"building a toy car from wire"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2h_L2_B', 'RC2h', 2, 'B', 'Writing a Difference', 'Paper, Pencil, Two printed passages', 'Read the two stories about the market again. Write one sentence telling me how they are DIFFERENT. (For example, ''In Story A..., but in Story B...'')', 'Child writes a sentence contrasting the two texts.', 'If they only describe one story, prompt: ''Tell me about the other story in the same sentence.''', 'What word did you use to show they are different? (e.g., but, however)', '{"default":{"theme":"market"},"ug":{"theme":"market (buying different things)"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2h_L2_C', 'RC2h', 2, 'C', 'Comparing Characters', 'Paper, Pencil, Two printed passages', 'Read the two stories. The main character in Story 1 is brave. Is the character in Story 2 brave, or something else? Write a sentence comparing the two characters.', 'Child writes a sentence comparing the traits of the two characters.', 'If they struggle, ask them to list what each character did.', 'How do their actions show they are different kinds of people?', '{"default":{"characters":"brave vs scared"},"ug":{"characters":"brave vs scared"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2h_L3_A', 'RC2h', 3, 'A', 'Detecting False Comparisons', 'Two printed passages', 'Read the two passages about bears. Someone wrote: ''Both passages say bears eat fish.'' Check the texts. Is that true?', 'Child verifies if the claim is supported by both texts.', 'If they only check one text, remind them to check the other.', 'Why is it important to check both texts before saying they are the same?', '{"default":{"animal":"bears"},"ug":{"animal":"lions"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2h_L3_B', 'RC2h', 3, 'B', 'Fixing a Venn Diagram Error', 'Two printed passages, A drawn Venn diagram with one error', 'Look at this Venn diagram comparing the two stories. I put ''has a dog'' in the middle (Both) section. But I made a mistake! Where should ''has a dog'' actually go?', 'Child identifies the error and moves the trait to the correct section.', 'If they don''t see the error, have them scan both stories for the word ''dog''.', 'Why doesn''t it belong in the middle?', '{"default":{"trait":"has a dog"},"ug":{"trait":"has a dog"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2h_L3_C', 'RC2h', 3, 'C', 'Identifying the Better Source', 'Two printed passages', 'We need to learn how to plant seeds. Read Text A (a story about a boy planting seeds) and Text B (a list of instructions for planting). Which text is better if we want to learn HOW to do it?', 'Child selects the instructional text.', 'If they pick the story, ask: ''Does the story give us step-by-step directions?''', 'Why is Text B better for learning how to do something?', '{"default":{"topic":"planting seeds"},"ug":{"topic":"planting maize"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2h_L4_A', 'RC2h', 4, 'A', 'Writing a Comparative Paragraph', 'Paper, Pencil, Two printed passages', 'Read the two passages about different types of houses. Write a short paragraph. Start by saying one way they are the same, then tell one way they are different.', 'Child writes a cohesive paragraph comparing and contrasting the texts.', 'If they struggle with structure, provide a frame: ''Both houses... However, House A...''', 'Did you include both a similarity and a difference?', '{"default":{"topic":"houses"},"ug":{"topic":"houses (brick vs mud/wattle)"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2h_L4_B', 'RC2h', 4, 'B', 'Generating a Companion Text', 'Printed passage, Paper, Pencil', 'Read this short story about a rainy day. Now, write your own very short story about a sunny day. Try to make your character do the opposite of the character in the first story.', 'Child writes a contrasting narrative based on a model text.', 'If their story is identical, emphasize doing the ''opposite''.', 'How is your sunny day story different from the rainy day story?', '{"default":{"theme":"weather opposite"},"ug":{"theme":"weather opposite"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2h_L4_C', 'RC2h', 4, 'C', 'Explaining Author''s Purpose in Comparing', 'Two printed passages', 'Read the two texts about the same event (e.g., a football game). One is written by a fan of the winning team, one by a fan of the losing team. Explain to me why the two stories sound so different.', 'Child articulates that perspective changes how a story is told.', 'If they say ''one is lying'', explain perspective and feelings.', 'How do the authors'' feelings change the way they wrote their stories?', '{"default":{"theme":"sports game"},"ug":{"theme":"football match"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2h_L4_M', 'RC2h', 4, 'M', 'Comparing Real-World Options', 'Two printed menus or advertisements, Paper, Pencil', 'Here are flyers for two different schools (or camps). Read both. Write down one thing both schools have, and one thing that makes them different from each other.', 'Child extracts similarities and differences from functional texts.', 'Do not correct during the task. If they fail, review Venn diagrams and explicit comparison.', 'If you had to choose, which one would you pick based on the differences?', '{"default":{"theme":"camps"},"ug":{"theme":"schools"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2i_L1_A', 'RC2i', 1, 'A', 'Auditory Feature Identification', 'A non-fiction book with a glossary/index', 'I''m going to read a word from the back of this book, and then tell you what page it is on. What part of the book am I looking at: the title, or the index?', 'Child identifies the index.', 'If they guess title, show them the front cover vs the back pages.', 'What does an index help us do?', '{"default":{"feature":"index"},"ug":{"feature":"index"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2i_L1_B', 'RC2i', 1, 'B', 'Physical Scavenger Hunt', 'A non-fiction book or printed article with headings, bold words, and captions', 'Let''s go on a scavenger hunt in this book. Point to a bold word. Now point to a heading. Now point to a picture caption.', 'Child successfully locates the requested text features.', 'If they struggle, describe what the feature looks like (e.g., ''dark, thick letters'').', 'Why do you think the author made some words bold?', '{"default":{"features":"bold, heading, caption"},"ug":{"features":"bold, heading, caption"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2i_L1_C', 'RC2i', 1, 'C', 'Verbal Feature Purpose', 'Printed article with a picture and caption', 'Look at this picture of a lion. Underneath, there is a small sentence that says ''Lions rest in the shade''. This is called a caption. What is the job of a caption?', 'Child explains that a caption tells about the picture.', 'If they don''t know, ask them to look at the picture and read the sentence again.', 'Could we understand the picture better with or without the caption?', '{"default":{"animal":"lion"},"ug":{"animal":"lion"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2i_L2_A', 'RC2i', 2, 'A', 'Writing a Caption', 'Paper, Pencil, A picture or drawing', 'Look at this picture (e.g., a child riding a bike). It needs a caption! Tell me a sentence that explains the picture, then write it underneath.', 'Child composes and writes a relevant caption.', 'If the caption is unrelated, remind them it must describe exactly what is in the image.', 'How does your caption help someone understand the picture?', '{"default":{"picture":"riding a bike"},"ug":{"picture":"riding a bicycle with matooke"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2i_L2_B', 'RC2i', 2, 'B', 'Using a Heading', 'Paper, Pencil, Printed article with headings', 'Read the headings in this article. Which section would you read to learn what elephants eat? Write down the heading of that section.', 'Child identifies the correct heading (e.g., ''Diet'' or ''What They Eat'') and writes it.', 'If they write the whole paragraph, explain they only need the title of the section.', 'How do headings save us time when we are reading?', '{"default":{"animal":"elephants"},"ug":{"animal":"elephants"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2i_L2_C', 'RC2i', 2, 'C', 'Extracting from a Table', 'Paper, Pencil, A simple printed table/chart', 'Look at this table showing how many books different children read. Find Amara''s name. How many books did she read? Write the number down.', 'Child successfully navigates the rows and columns to find the data.', 'If they pick the wrong number, trace the row from the name to the number with their finger.', 'Why is a table sometimes easier to read than a long paragraph?', '{"default":{"table":"books read"},"ug":{"table":"books read by local children"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2i_L3_A', 'RC2i', 3, 'A', 'Detecting a Mismatched Caption', 'Printed picture with an incorrect caption', 'Look at this picture of a dog sleeping. The caption says: ''The dog is running fast.'' What is wrong, and how would you fix it?', 'Child identifies the mismatch and suggests a better caption.', 'If they don''t see the error, ask them to compare the action in the picture to the action in the words.', 'Why must the caption match the picture?', '{"default":{"picture":"sleeping dog"},"ug":{"picture":"sleeping dog"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2i_L3_B', 'RC2i', 3, 'B', 'Spotting Heading Errors', 'Printed article with mixed-up headings', 'Look at this article. The heading says ''What They Eat'', but the paragraph is about where the animal lives! Which heading should be there instead?', 'Child identifies the error and suggests a better heading (e.g., ''Habitat'' or ''Where They Live'').', 'If they are confused, read the paragraph aloud and ask what the main idea is.', 'Why is a wrong heading confusing for a reader?', '{"default":{"heading":"What They Eat vs Habitat"},"ug":{"heading":"What They Eat vs Habitat"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2i_L3_C', 'RC2i', 3, 'C', 'Evaluating Text Formats', 'Printed paragraph vs printed list', 'Here is a recipe written as one long paragraph, and the same recipe written as a numbered list. Which one is easier to follow when you are cooking, and why?', 'Child selects the list and explains that it separates the steps clearly.', 'If they choose the paragraph, ask them to quickly find step 3 in both formats.', 'Why do authors use lists instead of paragraphs sometimes?', '{"default":{"format":"recipe"},"ug":{"format":"recipe for chapati"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2i_L4_A', 'RC2i', 4, 'A', 'Formatting a Text', 'Paper, Pencil, A block of unformatted text', 'Here is a lot of information about lions. Rewrite it on your paper, but add a Title, at least one Heading, and underline the most important word to make it ''bold''.', 'Child structures the raw text into a formatted informational piece.', 'If they just copy it as a block, remind them of the features they need to add.', 'How does adding these features make your writing look better?', '{"default":{"animal":"lions"},"ug":{"animal":"lions"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2i_L4_B', 'RC2i', 4, 'B', 'Creating a Table', 'Paper, Pencil', 'Ask three people in the house (or invent three people) what their favorite fruit is. Create a simple table or chart to show the answers. Make sure it has labels!', 'Child constructs a functional table organizing data.', 'If they just write a list, show them how to draw lines to make rows and columns.', 'How do the labels at the top of the table help us understand the data?', '{"default":{"data":"favorite fruit"},"ug":{"data":"favorite fruit (mango, jackfruit, banana)"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2i_L4_C', 'RC2i', 4, 'C', 'Teaching Text Features', 'A non-fiction book, Paper, Pencil', 'Explain to me why non-fiction books have things like tables of contents, glossaries, and indexes. Choose one of those features and write a sentence about how to use it.', 'Child articulates the purpose of navigational text features and writes a ''how-to'' sentence.', 'If they struggle, open the book to the index and ask them to find a specific word.', 'Do storybooks usually have an index? Why or why not?', '{"default":{"concept":"navigational features"},"ug":{"concept":"navigational features"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2i_L4_M', 'RC2i', 4, 'M', 'Navigating a Map/Diagram', 'A printed simple map or diagram with labels and a key, Paper, Pencil', 'Look at this map of a zoo. Use the map key to find where the lions are. Write down what is right next to the lions.', 'Child successfully uses the map key/labels to locate information and writes the answer.', 'Do not correct during the task. If they fail, review using diagrams and keys.', 'How did the map key help you find the answer?', '{"default":{"map":"zoo"},"ug":{"map":"wildlife park (Entebbe Zoo)"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2a_L1_A', 'RF2a', 1, 'A', 'Auditory Chunking', 'None', 'Listen to me read this sentence: ''The big dog... ran fast... to the park.'' Did I read it like a robot (word-by-word) or in chunks that make sense together?', 'Child identifies you read in chunks/groups of words.', 'If they say robot, demonstrate actual robot reading: ''The... big... dog... ran... fast...''', 'Why does it sound better when we group words together?', '{"default":{"animal":"dog","place":"park"},"ug":{"animal":"goat","place":"field"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2a_L1_B', 'RF2a', 1, 'B', 'Physical Chunk Tracing', 'Printed sentence with phrase boundaries marked (e.g., with swoops or lines under chunks)', 'Run your finger under the first group of words as you read them: ''The little boy''. Pause. Now the next group: ''went to the store''.', 'Child successfully sweeps finger under phrases and pauses at boundaries.', 'If they stop at every word, hold their finger and guide the smooth sweep.', 'How does sweeping your finger help you read the words together?', '{"default":{"phrase":"went to the store"},"ug":{"phrase":"went to the market"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2a_L1_C', 'RF2a', 1, 'C', 'Verbal Chunk Echoing', 'None', 'I''m going to say a group of words that belong together. You echo them back smoothly. ''in the morning'' (wait for echo). ''we ate breakfast'' (wait for echo).', 'Child echoes the phrases smoothly without breaking them into choppy words.', 'If they chop it up, repeat it smoothly and ask them to sing it like a song.', 'Did ''in the morning'' sound like one big idea or three separate ideas?', '{"default":{"phrase":"ate breakfast"},"ug":{"phrase":"drank tea"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2a_L2_A', 'RF2a', 2, 'A', 'Reading Marked Phrases', 'Printed passage with phrase boundaries marked (e.g., / or swoops)', 'Read this short paragraph out loud. Pause slightly wherever you see the slash mark (/). Try to make the words between the slashes flow together smoothly.', 'Child reads the passage, grouping words according to the provided boundaries.', 'If they ignore the marks, stop them and model the first sentence again.', 'Did pausing at the slashes make the story easier to understand?', '{"default":{"theme":"playing outside"},"ug":{"theme":"playing football"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2a_L2_B', 'RF2a', 2, 'B', 'Marking and Reading Phrases', 'Paper, Pencil, Printed passage (unmarked)', 'Read this sentence silently. Take your pencil and draw a slash (/) where you think a natural pause should go, separating the ''who'' from the ''what they did''. Then read it aloud.', 'Child correctly identifies phrase boundaries (e.g., subject/predicate or prepositional phrases) and reads it smoothly.', 'If they mark every word, remind them we are looking for groups of words that belong together.', 'Why did you put the pause right there?', '{"default":{"theme":"eating lunch"},"ug":{"theme":"eating lunch (posho and beans)"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2a_L2_C', 'RF2a', 2, 'C', 'Reading Fluency Practice', 'Printed passage', 'Read this paragraph out loud. Focus on reading in phrases, not word-by-word. Think about how you would say it if you were just talking to me.', 'Child reads the passage with conversational phrasing, abandoning word-by-word reading.', 'If choppy, have them read the same sentence three times until it smooths out.', 'Did it sound more like reading or more like talking?', '{"default":{"theme":"a windy day"},"ug":{"theme":"a rainy afternoon"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2a_L3_A', 'RF2a', 3, 'A', 'Detecting Choppy Reading', 'Printed passage', 'Listen to me read this sentence: ''The. Cat. Sat. On. The. Mat.'' Did I read that well? What did I do wrong?', 'Child identifies that you read word-by-word (choppy) instead of in phrases.', 'If they say it was good, ask: ''Is that how we talk?''', 'How should I read it instead?', '{"default":{"animal":"Cat"},"ug":{"animal":"Cat"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2a_L3_B', 'RF2a', 3, 'B', 'Detecting Wrong Phrasing', 'Printed passage', 'Listen to me read this: ''The boy walked to / the store to buy / some milk.'' Did my pauses sound natural, or did I break up groups of words that belong together?', 'Child identifies that the pauses were unnatural (splitting prepositional phrases or verb phrases awkwardly).', 'If they think it''s fine, read it again with proper phrasing and ask which sounds better.', 'Where should the pauses actually go?', '{"default":{"item":"milk"},"ug":{"item":"milk"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2a_L3_C', 'RF2a', 3, 'C', 'Choosing the Better Reading', 'Printed passage', 'I will read this sentence two ways. Way 1: ''The dog / ran fast / to the house.'' Way 2: ''The dog ran / fast to the / house.'' Which way made the story easier to understand?', 'Child selects Way 1, recognizing appropriate phrasing.', 'If they pick 2, ask them what ''fast to the'' means by itself.', 'Why is it confusing when we pause in the middle of an idea?', '{"default":{"animal":"dog"},"ug":{"animal":"goat"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2a_L4_A', 'RF2a', 4, 'A', 'Directing a Reader', 'Printed passage, Pencil', 'You are the director! Take this paragraph and draw slashes where I should pause. I will read it exactly how you mark it.', 'Child accurately marks phrase boundaries. Parent reads it as marked. Child evaluates.', 'If they put slashes in weird places, read it exactly as marked so they hear the awkwardness, then let them fix it.', 'How did my reading sound based on your marks?', '{"default":{"theme":"building a snowman"},"ug":{"theme":"building a fire"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2a_L4_B', 'RF2a', 4, 'B', 'Expressive Oral Reading', 'A favorite book or printed passage', 'Pick a page from this book. Practice reading it silently first, focusing on grouping words. Then, read it out loud to me like you are a storyteller on the radio.', 'Child prepares and delivers a fluent, phrased reading of the text.', 'If still choppy, select a shorter sentence and have them practice it repeatedly.', 'How did practicing silently help you read it out loud?', '{"default":{"format":"book page"},"ug":{"format":"book page"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2a_L4_C', 'RF2a', 4, 'C', 'Teaching Phrasing', 'Paper, Pencil', 'Explain to someone younger what ''reading in chunks'' means. Why is it important? Write one sentence showing a bad way to read, and one sentence explaining the good way.', 'Child articulates the concept of phrasing and its impact on comprehension/fluency.', 'If they struggle, ask: ''If you read every word like a robot, do you remember what the story is about?''', 'Why does reading smoothly help our brain understand the story better?', '{"default":{"concept":"phrasing"},"ug":{"concept":"phrasing"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2a_L4_M', 'RF2a', 4, 'M', 'Cold Read Fluency', 'A new, unseen printed passage, Audio recording device (optional)', 'Here is a story you haven''t seen before. Read it out loud to me. Do your best to make it sound smooth and interesting, not choppy.', 'Child demonstrates generalized fluency and phrasing on a cold read.', 'Do not correct during the reading. Note areas of choppiness for future practice. If highly choppy, return to Execute level.', 'Did you feel like you were grouping words together as you read?', '{"default":{"theme":"a surprise party"},"ug":{"theme":"a surprise visitor"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2b_L1_A', 'RF2b', 1, 'A', 'Auditory Rate Identification', 'None', 'Listen to me read this sentence. (Read very fast). Now listen again. (Read very slow). Which way was easier to understand and why?', 'Child identifies that neither extreme is good; a middle pace is best.', 'If they prefer the fast one, ask them to repeat what you just said.', 'Why is reading too fast a problem?', '{"default":{"speed":"fast vs slow"},"ug":{"speed":"fast vs slow"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2b_L1_B', 'RF2b', 1, 'B', 'Physical Pacing', 'Printed passage', 'I am going to read this passage at a ''just right'' walking pace. Try to point to the words exactly as I say them, not too fast, not too slow.', 'Child tracks the text accurately at a fluent conversational pace.', 'If they lag behind or speed ahead, guide their finger to match your voice.', 'Did we move our fingers like a race car, or like someone taking a walk?', '{"default":{"pace":"walking"},"ug":{"pace":"walking"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2b_L1_C', 'RF2b', 1, 'C', 'Verbal Rate Check', 'None', 'If I read so fast that I skip words and get out of breath, am I reading at a good rate? What if I read so slow I forget what the beginning of the sentence was about?', 'Child articulates that both extremes hinder comprehension.', 'If they don''t know, explain the concept of a ''talking speed''.', 'What speed should we aim for when reading out loud?', '{"default":{"concept":"reading speed"},"ug":{"concept":"reading speed"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2b_L2_A', 'RF2b', 2, 'A', 'Timed Repeated Reading', 'Printed passage, Timer/Stopwatch', 'Read this paragraph out loud. I will time you. Don''t rush and make mistakes, just read smoothly. Ready? Go.', 'Child reads the passage. Note the time. (Goal is age-appropriate WPM, usually 60-90 WPM in Band 2).', 'If they read too fast and make many errors, say: ''This isn''t a race. Accuracy is more important than speed.''', 'Did you feel rushed, or did it feel like a comfortable speed?', '{"default":{"theme":"baking"},"ug":{"theme":"cooking"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2b_L2_B', 'RF2b', 2, 'B', 'Beat the Timer (Accuracy Focus)', 'Printed passage, Timer/Stopwatch', 'You read that paragraph in 45 seconds last time. Let''s read it again. Try to beat your time, BUT if you make a mistake, you have to go back and fix it.', 'Child reads the passage slightly faster due to familiarity, maintaining accuracy.', 'If they speed read and ignore errors, stop the timer. ''We have to read it right first.''', 'Why was it easier to read it faster the second time?', '{"default":{"theme":"baking"},"ug":{"theme":"cooking"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2b_L2_C', 'RF2b', 2, 'C', 'Reading with a Metronome/Pacer', 'Printed passage', 'I will tap my finger on the table in a steady beat. Try to read the words to match my steady beat. Don''t speed up!', 'Child maintains a steady reading rate without rushing or dragging.', 'If they ignore the beat, stop and have them just say ''da da da'' to the beat first.', 'How does keeping a steady beat help your reading sound better?', '{"default":{"theme":"a long walk"},"ug":{"theme":"walking to school"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2b_L3_A', 'RF2b', 3, 'A', 'Evaluating Reader Rate', 'Printed passage', 'Listen to me read this paragraph. (Read it slightly too fast, slurring some words). Give me advice: Should I speed up, slow down, or keep the same speed?', 'Child identifies you are reading too fast and advises slowing down.', 'If they say it was good, ask: ''Could you understand every word I said?''', 'Why is reading that fast a bad idea?', '{"default":{"passage":"parent reads fast"},"ug":{"passage":"parent reads fast"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2b_L3_B', 'RF2b', 3, 'B', 'The Accuracy Trade-off', 'Printed passage', 'If a student reads 100 words in a minute but gets 20 of them wrong, and another student reads 60 words in a minute and gets all of them right, who is the better reader?', 'Child identifies the slower, accurate reader as better.', 'If they pick the fast one, explain that reading is about understanding, not just speed.', 'Why doesn''t speed matter if you get the words wrong?', '{"default":{"concept":"accuracy vs speed"},"ug":{"concept":"accuracy vs speed"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2b_L3_C', 'RF2b', 3, 'C', 'Identifying Punctuation Pauses', 'Printed passage', 'Read this sentence. It has commas and a full stop. When you read fast, you might ignore them. Read it at a good rate, and make sure I hear you pause at the punctuation.', 'Child reads at a controlled rate, observing punctuation boundaries.', 'If they barrel through commas, have them read it again and clap at every comma.', 'How does punctuation control how fast we read?', '{"default":{"punctuation":"commas and periods"},"ug":{"punctuation":"commas and full stops"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2b_L4_A', 'RF2b', 4, 'A', 'Setting the Pace', 'A printed poem or rhythmic text', 'You are in charge of how fast we read this poem together. Read it out loud, and I will try to match your exact speed. Make sure you pick a good ''talking speed.''', 'Child sets and maintains an appropriate reading rate while reading chorally with the parent.', 'If they read too fast, the parent should struggle to keep up intentionally to demonstrate.', 'Was it hard to keep the same speed the whole time?', '{"default":{"theme":"poem"},"ug":{"theme":"poem"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2b_L4_B', 'RF2b', 4, 'B', 'Adjusting Rate for Purpose', 'Two short printed sentences (one urgent, one sleepy)', 'Look at sentence A: ''Quick, the bus is leaving!'' Look at sentence B: ''The old turtle slowly went to sleep.'' Read them out loud. Should you read them at the exact same speed?', 'Child reads sentence A faster and sentence B slower, adjusting rate for meaning.', 'If they read both identically, ask them what is happening in each sentence.', 'Why did you change your speed for the second sentence?', '{"default":{"theme":"urgent vs slow"},"ug":{"theme":"urgent vs slow"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2b_L4_C', 'RF2b', 4, 'C', 'Self-Evaluation', 'Printed passage, Timer', 'Read this paragraph. Time yourself. When you finish, tell me: Did I read too fast, too slow, or just right? Did I understand what I read?', 'Child reads, self-monitors their rate, and evaluates their comprehension.', 'If their self-evaluation doesn''t match reality (e.g., they rushed but say it was perfect), provide gentle feedback.', 'How do you know if you are reading at the right speed?', '{"default":{"theme":"a busy day"},"ug":{"theme":"a busy day"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2b_L4_M', 'RF2b', 4, 'M', 'Reading a Story to an Audience', 'A familiar storybook or printed story', 'I want you to read this story to your younger sibling (or a stuffed animal/pet). Read it at a speed that helps them understand and enjoy the story.', 'Child demonstrates appropriate reading rate and fluency in an authentic read-aloud context.', 'Do not correct during the reading. Evaluate if the rate facilitated comprehension for the audience.', 'Did you have to slow down so they could understand the story better?', '{"default":{"audience":"sibling"},"ug":{"audience":"sibling"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2c_L1_A', 'RF2c', 1, 'A', 'Auditory Emotion Matching', 'None', 'Listen to me say this: ''I can''t believe we are going to the zoo!'' Did my voice go up or down at the end? Did I sound bored or excited?', 'Child identifies the pitch going up and the excited tone.', 'If they say bored, say it again completely flat, then contrast with the excited version.', 'How does my voice change when I''m excited?', '{"default":{"theme":"zoo"},"ug":{"theme":"wildlife park"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2c_L1_B', 'RF2c', 1, 'B', 'Physical Punctuation Action', 'None', 'When I read a sentence that ends in a question mark (?), shrug your shoulders. When it ends in an exclamation mark (!), throw your hands up. ''Where is the dog?'' (wait). ''There he is!'' (wait).', 'Child physically responds to the auditory cues of different sentence types.', 'If they miss the cue, explain that our voice goes up for a question and gets loud/strong for an exclamation.', 'How does your voice tell someone there is a question mark at the end of the sentence?', '{"default":{"animal":"dog"},"ug":{"animal":"goat"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2c_L1_C', 'RF2c', 1, 'C', 'Verbal Echo with Expression', 'None', 'I''m going to say a sentence in a grumpy voice. You echo it back in the exact same grumpy voice. ''I don''t want to eat my vegetables.''', 'Child accurately mimics the tone and inflection.', 'If they say it normally, exaggerate the grumpiness and ask them to act like an actor.', 'How did making your voice grumpy change the meaning of the words?', '{"default":{"food":"vegetables"},"ug":{"food":"cabbage"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2c_L2_A', 'RF2c', 2, 'A', 'Reading with Punctuation', 'Printed sentences with varied end punctuation', 'Read these three sentences out loud. Make sure your voice tells me which one has a full stop, which has a question mark, and which has an exclamation mark.', 'Child reads the sentences with appropriate inflection (flat, rising pitch, strong emphasis).', 'If they read them all the same, model the difference and have them repeat.', 'How did your voice change for the question?', '{"default":{"sentences":"The cat is here. Is the cat here? The cat is here!"},"ug":{"sentences":"The cat is here. Is the cat here? The cat is here!"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2c_L2_B', 'RF2c', 2, 'B', 'Emphasizing Key Words', 'Printed sentence with one word bolded', 'Read this sentence, but make your voice extra strong on the bold word: ''I did **not** eat the last cookie.'' Now read it again emphasizing a different word: ''**I** did not eat the last cookie.''', 'Child successfully shifts emphasis to change the nuance of the sentence.', 'If they struggle, say it for them and ask them to copy.', 'How does changing the strong word change the meaning of the sentence?', '{"default":{"food":"cookie"},"ug":{"food":"mandazi"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2c_L2_C', 'RF2c', 2, 'C', 'Character Voices', 'Printed dialogue passage', 'Read this story where a big bear is talking to a tiny mouse. Use a deep voice for the bear, and a squeaky voice for the mouse.', 'Child distinguishes speakers by altering pitch and tone.', 'If they use their normal voice, remind them: ''You are an actor right now. Be the bear!''', 'How do character voices make a story more fun to listen to?', '{"default":{"characters":"bear and mouse"},"ug":{"characters":"lion and mouse"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2c_L3_A', 'RF2c', 3, 'A', 'Detecting Mismatched Tone', 'Printed passage', 'Listen to me read this scary part of a story. (Read it in a very happy, cheerful voice). Did my voice match what was happening in the story?', 'Child identifies the mismatch between content and tone.', 'If they say it was fine, ask: ''If something scary is happening, do people sound happy?''', 'How should I have used my voice instead?', '{"default":{"theme":"scary story"},"ug":{"theme":"scary story"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2c_L3_B', 'RF2c', 3, 'B', 'Fixing the Question Pitch', 'Printed sentence', 'I''m going to read this question: ''Where are my shoes.'' (Read it with a flat, falling pitch like a statement). What did I forget to do with my voice at the end?', 'Child identifies that the pitch should rise at the end of a question.', 'If they don''t know, model the correct rising pitch.', 'Can you read it the right way?', '{"default":{"item":"shoes"},"ug":{"item":"shoes"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2c_L3_C', 'RF2c', 3, 'C', 'Choosing the Right Emphasis', 'Printed sentence', 'Look at this sentence: ''That is a huge dog!'' Which word should we say the loudest to make it sound right? Huge or dog?', 'Child selects ''huge'' to emphasize the descriptive element.', 'If they select ''dog'', read it both ways and ask which sounds more natural.', 'Why does emphasizing ''huge'' make the sentence better?', '{"default":{"animal":"dog","adjective":"huge"},"ug":{"animal":"dog","adjective":"huge"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2c_L4_A', 'RF2c', 4, 'A', 'Marking Text for Expression', 'Printed passage, Highlighter or Pencil', 'Read this paragraph silently. Think about how it should sound. Underline two words that you think should be read LOUDLY or with strong feeling. Then read it out loud to me.', 'Child independently selects words for emphasis and executes the reading accordingly.', 'If they underline random words like ''the'', ask: ''Does emphasizing *the* change the meaning?''', 'Why did you choose to make those specific words strong?', '{"default":{"theme":"a big surprise"},"ug":{"theme":"a big surprise"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2c_L4_B', 'RF2c', 4, 'B', 'Writing Dialogue with Emotion Cues', 'Paper, Pencil', 'Write a short sentence of dialogue where someone is whispering because they are hiding. Then write a sentence where they are shouting because they are angry.', 'Child composes sentences that implicitly demand specific prosodic delivery.', 'If the content doesn''t match the emotion, prompt them to think about what people say when hiding/angry.', 'Read your sentences out loud to me using the right voices.', '{"default":{"emotions":"whispering vs shouting"},"ug":{"emotions":"whispering vs shouting"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2c_L4_C', 'RF2c', 4, 'C', 'Explaining Punctuation Power', 'Paper, Pencil', 'Explain to me why punctuation marks are like road signs for our voice when we read out loud. Give an example.', 'Child articulates that punctuation dictates stops, pauses, and pitch changes.', 'If they struggle, ask: ''What happens if we ignore a stop sign on the road? What if we ignore a full stop in a book?''', 'How does a question mark tell your voice what to do?', '{"default":{"concept":"punctuation as signals"},"ug":{"concept":"punctuation as signals"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RF2c_L4_M', 'RF2c', 4, 'M', 'Radio Play Reading', 'A printed script or dialogue-heavy passage', 'We are going to do a radio play! You read this part, and I''ll read this part. You have to use your voice to show exactly how your character feels.', 'Child reads their part fluently, integrating appropriate phrasing, rate, and expressive prosody.', 'Do not correct during the performance. If flat and robotic, review Execute level tasks.', 'Did you feel like you were acting with your voice?', '{"default":{"format":"script"},"ug":{"format":"script"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2j_L1_A', 'RC2j', 1, 'A', 'Auditory Rhyme Identification', 'None', 'Listen to this short poem: ''The fat cat / sat on the mat.'' Which words rhyme? What sound do they all have at the end?', 'Child identifies cat, sat, mat and the /at/ sound.', 'If they don''t hear it, emphasize the ends of the words: c-AT, s-AT.', 'Why do poems often use rhyming words?', '{"default":{"words":"cat, sat, mat"},"ug":{"words":"cat, sat, mat"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2j_L1_B', 'RC2j', 1, 'B', 'Physical Rhythm Clapping', 'None', 'I am going to say a rhyme. I want you to clap on the strong beats with me. ''Hickory dickory dock, the mouse ran up the clock.''', 'Child claps along with the metrical rhythm of the text.', 'If they clap on every syllable, guide their hands to only clap the stressed beats.', 'Did that sound like a regular story, or more like a song?', '{"default":{"poem":"nursery rhyme"},"ug":{"poem":"nursery rhyme or local chant"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2j_L1_C', 'RC2j', 1, 'C', 'Visual Line Break Awareness', 'A printed poem and a printed paragraph', 'Look at this poem, and look at this regular story paragraph. How do they look different on the page? Look at where the lines end.', 'Child identifies that poems have short lines and don''t go all the way to the edge of the page.', 'If they don''t see it, trace the ragged right edge of the poem vs the blocky paragraph.', 'Why do you think the poet chopped the lines up like that?', '{"default":{"format":"poem vs prose"},"ug":{"format":"poem vs prose"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2j_L2_A', 'RC2j', 2, 'A', 'Completing a Rhyme', 'Paper, Pencil, Printed poem missing the last word', 'Read this poem. The very last word is missing. Think of a word that makes sense AND rhymes with the line above it. Tell it to me, then write it in the blank.', 'Child orally provides and writes a valid rhyming word that fits the context.', 'If it doesn''t rhyme, ask: ''What word does it need to sound like?'' If it doesn''t make sense, ask: ''Does that fit the story?''', 'How did you know that was the right word to use?', '{"default":{"rhyme":"sun / fun"},"ug":{"rhyme":"sun / fun"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2j_L2_B', 'RC2j', 2, 'B', 'Writing Rhyming Pairs', 'Paper, Pencil', 'Think of a word that rhymes with ''tree''. Now write a very short two-line poem using those two words at the ends of the lines. Say it out loud first.', 'Child composes and writes a simple rhyming couplet.', 'If the lines don''t make sense together, prompt them to connect the ideas.', 'Read your poem out loud. Does it have a rhythm to it?', '{"default":{"word":"tree"},"ug":{"word":"tree"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2j_L2_C', 'RC2j', 2, 'C', 'Reading with Rhythm', 'Printed poem', 'Read this poem out loud. Pay attention to the line breaks. Pause slightly at the end of each line, even if there isn''t a full stop, so we can hear the rhythm.', 'Child reads the poem, honoring line breaks and emphasizing the meter.', 'If they read it like prose (running lines together), model the rhythmic pauses and have them try again.', 'How does pausing at the end of the line help the poem sound better?', '{"default":{"theme":"stars"},"ug":{"theme":"stars"}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('RC2j_L3_A', 'RC2j', 3, 'A', 'Detecting a Broken Rhyme', 'Printed poem', 'Listen to this: ''Roses are red, violets are blue, sugar is sweet, and I like orange.'' Does that sound like a good poem? What went wrong at the end?', 'Child identifies that the rhyming pattern was broken.', 'If they don''t hear it, ask: ''Does orange rhyme with blue?''', 'What word could we use instead to fix the rhyme?', '{"default":{"broken_rhyme":"blue / orange"},"ug":{"broken_rhyme":"blue / orange"}}', 0);